import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { getQuestionSets } from "../../../../../lib/questions/get_question_sets.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    const { userId } = await req.json();
    if (!userId) return new Response(JSON.stringify({ error: "Missing userId" }), { status: 400 });

    const sets = await getQuestionSets(supabase, userId);
    return new Response(JSON.stringify(sets), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});
